export default function ThemedIcon({ name, size = 20, color, className = '', style = {}, fill = false }) {
  const IconComponent = ICONS[name] || ICONS['cat-other'];

  return (
    <span
      className={`inline-flex items-center justify-center flex-shrink-0 transition-colors ${className}`}
      style={{ width: size, height: size, color: color || 'currentColor', ...style }}
    >
      <IconComponent filled={fill} />
    </span>
  );
}
